(window.webpackJsonp=window.webpackJsonp||[]).push([[301],{928:function(n,e){n.exports="\x3c!-- \ntitle: 41-Express入门\nsort: \n--\x3e \n\n## Request\n\n- `req.body`：客户端请求体的数据，表单或 JSON 数据\n- `req.params`：请求 URI 中的路径参数\n- `req.query`：请求 URI 中的查询参数\n- `req.cookies`：客户端的 cookies\n\n## Response\n\n```js\n// 发送内容\nres.send('HTML String');\n\n// 发送文件\nres.sendFile('file.zip');\n\n// 渲染模板并发送\nres.render('index');\n\n// 设置状态码为 404，并返回字符串\nres.status(404).send('Page Not Found');\n```\n\n## 路由\n\n```\napp.get('/', handle)\n```\n\n## nodemon\n\n> `npm install nodemon --save-dev`"}}]);